// @google/genai Coding Guidelines: All usages of the Gemini API have been updated to adhere to the latest SDK best practices.
import { GoogleGenAI, Type } from "@google/genai";
import { MOCK_ANALYTICS_DATA } from '../constants';
import { WordAnalysis } from '../types';

let genAI: GoogleGenAI | null = null;

function getAiClient(): GoogleGenAI {
    if (!genAI) {
        if (!process.env.API_KEY) {
            console.error("API_KEY environment variable not set!");
            throw new Error("API_KEY environment variable not set!");
        }
        genAI = new GoogleGenAI({apiKey: process.env.API_KEY});
    }
    return genAI;
}

export const getMockAnalytics = (): Promise<any[]> => {
    return new Promise(resolve => setTimeout(() => resolve(MOCK_ANALYTICS_DATA), 500));
};

export const moderateChatMessage = async (message: string): Promise<{ isAggressive: boolean }> => {
    try {
        const ai = getAiClient();
        const prompt = `Is the following message aggressive, hateful, bullying, or highly inappropriate? Answer with only "yes" or "no".\n\nMessage: "${message}"`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
        });

        const text = response.text?.trim().toLowerCase() || 'no';
        return { isAggressive: text.includes('yes') };
    } catch (error) {
        console.error("Error moderating chat message:", error);
        return { isAggressive: false };
    }
};

export const getSupportResponse = async (question: string): Promise<string> => {
    try {
        const ai = getAiClient();
        const prompt = `You are the Alileva Global Gaming Platform Assistant. Answer the following user question politely. If asked about the platform, explain that it offers Chess, Word Master, Checkers, and Monopoly. User question: "${question}"`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
        });

        return response.text || "I'm sorry, I couldn't process that right now.";
    } catch (error) {
        console.error("Error getting support response:", error);
        return "Sorry, our support systems are currently busy. Please try again later.";
    }
};

export const getWordAnalysis = async (word: string, detailLevel: 'basic' | 'full'): Promise<WordAnalysis | null> => {
    if (!word) return null;

    const ai = getAiClient();

    const fullSchema = {
        type: Type.OBJECT,
        properties: {
            definition: { type: Type.STRING },
            synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
            antonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
            example: { type: Type.STRING },
            etymology: { type: Type.STRING },
            score: { type: Type.INTEGER },
        }
    };

    const basicSchema = {
        type: Type.OBJECT,
        properties: {
            definition: { type: Type.STRING },
            score: { type: Type.INTEGER },
        }
    };

    const prompt = `Provide a detailed analysis for the word "${word}". Also provide a reasonable point score as if it were a Scrabble word.`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                temperature: 0.2,
                responseSchema: detailLevel === 'full' ? fullSchema : basicSchema,
            }
        });

        const jsonText = response.text?.trim() || '{}';
        return JSON.parse(jsonText) as WordAnalysis;

    } catch (error) {
        console.error("Error getting word analysis:", error);
        return { definition: 'Sorry, there was an error analyzing this word.' };
    }
};

export const suggestBestWord = async (tiles: string[]): Promise<{ word: string, points: number } | null> => {
    if (tiles.length === 0) return null;

    const ai = getAiClient();
    const prompt = `Given the following Scrabble tiles, what is the highest-scoring word that can be formed? The tiles are: ${tiles.join(', ')}. Provide the word and its calculated score.`;

    const schema = {
        type: Type.OBJECT,
        properties: {
            word: { type: Type.STRING },
            points: { type: Type.INTEGER },
        },
    };

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: schema,
            },
        });

        const jsonText = response.text?.trim() || '{}';
        return JSON.parse(jsonText);
    } catch (error) {
        console.error("Error suggesting best word:", error);
        return null;
    }
};

import React, { useState, useEffect, useCallback } from 'react';
import { TranslationMessages } from '../../translations';

interface CheckersGameProps {
  t: (key: keyof TranslationMessages | string) => string;
}

type Color = 'white' | 'black';
type Piece = { color: Color; isKing: boolean } | null;

const createInitialBoard = (): Piece[][] => {
    const board: Piece[][] = Array.from({ length: 8 }, () => Array(8).fill(null));
    for (let row = 0; row < 3; row++) {
        for (let col = 0; col < 8; col++) {
            if ((row + col) % 2 !== 0) board[row][col] = { color: 'black', isKing: false };
        }
    }
    for (let row = 5; row < 8; row++) {
        for (let col = 0; col < 8; col++) {
            if ((row + col) % 2 !== 0) board[row][col] = { color: 'white', isKing: false };
        }
    }
    return board;
};

const CheckersGame: React.FC<CheckersGameProps> = ({ t }) => {
    const [board, setBoard] = useState<Piece[][]>(createInitialBoard());
    const [turn, setTurn] = useState<Color>('white');
    const [selected, setSelected] = useState<[number, number] | null>(null);
    const [validMoves, setValidMoves] = useState<[number, number][]>([]);

    const getMoves = useCallback((row: number, col: number, currentBoard: Piece[][]) => {
        const piece = currentBoard[row][col];
        if (!piece) return [];
        const moves: [number, number][] = [];
        const directions = piece.isKing ? [[-1, -1], [-1, 1], [1, -1], [1, 1]] : (piece.color === 'white' ? [[-1, -1], [-1, 1]] : [[1, -1], [1, 1]]);

        directions.forEach(([dr, dc]) => {
            const nr = row + dr;
            const nc = col + dc;
            if (nr >= 0 && nr < 8 && nc >= 0 && nc < 8) {
                if (!currentBoard[nr][nc]) {
                    moves.push([nr, nc]);
                } else if (currentBoard[nr][nc]?.color !== piece.color) {
                    const jr = nr + dr;
                    const jc = nc + dc;
                    if (jr >= 0 && jr < 8 && jc >= 0 && jc < 8 && !currentBoard[jr][jc]) {
                        moves.push([jr, jc]);
                    }
                }
            }
        });
        return moves;
    }, []);

    const handleSquareClick = (r: number, c: number) => {
        if (selected) {
            const move = validMoves.find(([mr, mc]) => mr === r && mc === c);
            if (move) {
                const newBoard = board.map(row => [...row]);
                const piece = newBoard[selected[0]][selected[1]];
                newBoard[r][c] = piece;
                newBoard[selected[0]][selected[1]] = null;

                // Handle Capture
                if (Math.abs(r - selected[0]) === 2) {
                    const cr = (r + selected[0]) / 2;
                    const cc = (c + selected[1]) / 2;
                    newBoard[cr][cc] = null;
                }

                // Handle Kinging
                if (piece && ((piece.color === 'white' && r === 0) || (piece.color === 'black' && r === 7))) {
                    piece.isKing = true;
                }

                setBoard(newBoard);
                setTurn(turn === 'white' ? 'black' : 'white');
                setSelected(null);
                setValidMoves([]);
            } else {
                setSelected(null);
                setValidMoves([]);
            }
        } else {
            const piece = board[r][c];
            if (piece && piece.color === turn) {
                setSelected([r, c]);
                setValidMoves(getMoves(r, c, board));
            }
        }
    };

    return (
        <div className="flex flex-col items-center justify-center p-4">
            <h2 className="text-2xl font-bold text-white mb-4">{turn === 'white' ? t('whites_turn') : t('blacks_turn')}</h2>
            <div className="grid grid-cols-8 border-4 border-amber-900 rounded shadow-2xl overflow-hidden bg-amber-100">
                {board.map((row, r) => row.map((piece, c) => {
                    const isDark = (r + c) % 2 !== 0;
                    const isSelected = selected && selected[0] === r && selected[1] === c;
                    const isValidMove = validMoves.some(([mr, mc]) => mr === r && mc === c);

                    return (
                        <div 
                            key={`${r}-${c}`} 
                            onClick={() => handleSquareClick(r, c)}
                            className={`w-10 h-10 sm:w-16 sm:h-16 flex items-center justify-center relative ${isDark ? 'bg-amber-800' : 'bg-amber-200'}`}
                        >
                            {piece && (
                                <div className={`w-4/5 h-4/5 rounded-full shadow-lg border-2 ${piece.color === 'white' ? 'bg-gray-100 border-gray-400' : 'bg-gray-900 border-gray-700'} ${isSelected ? 'ring-4 ring-yellow-400' : ''} flex items-center justify-center`}>
                                    {piece.isKing && <span className="text-yellow-500 font-bold text-lg">★</span>}
                                </div>
                            )}
                            {isValidMove && <div className="absolute inset-0 bg-emerald-500/30 cursor-pointer border-2 border-emerald-500" />}
                        </div>
                    );
                }))}
            </div>
            <button onClick={() => setBoard(createInitialBoard())} className="mt-8 bg-brand-primary py-2 px-6 rounded text-white font-bold">{t('play_again')}</button>
        </div>
    );
};

export default CheckersGame;

import React, { useState } from 'react';
